    #[test]
    fn test_invalid_transition() {
        let mut sm = ImpersonationSessionStateMachine::from_state(ImpersonationSessionState::Ended);
        // End is not valid from Ended state
        let result = sm.transition(ImpersonationSessionTransition::End);
        assert!(result.is_err());
    }

